import { Component, Input, Output, EventEmitter } from '@angular/core';
import { NgIf } from '@angular/common';

@Component({
  standalone: true,
  selector: 'app-user-card',
  imports: [NgIf],
  template: `
    <div class="card">
      <h2>{{ user.name }}</h2>
      <p *ngIf="user.bio">{{ user.bio }}</p>
      <button (click)="onSelect()">Select</button>
    </div>
  `
})
export class UserCardComponent {
  @Input() user!: { name: string; bio?: string };
  @Output() selected = new EventEmitter<void>();

  onSelect() {
    this.selected.emit();
  }
}

import { Directive, ElementRef, HostListener, Input } from '@angular/core';

@Directive({
  standalone: true,
  selector: '[appHighlight]'
})
export class HighlightDirective {
  @Input() appHighlight = 'yellow';

  constructor(private el: ElementRef) {}

  @HostListener('mouseenter') onMouseEnter() {
    this.el.nativeElement.style.backgroundColor = this.appHighlight;
  }

  @HostListener('mouseleave') onMouseLeave() {
    this.el.nativeElement.style.backgroundColor = '';
  }
}

import { Pipe, PipeTransform } from '@angular/core';

@Pipe({
  standalone: true,
  name: 'truncate'
})
export class TruncatePipe implements PipeTransform {
  transform(value: string, limit = 50, trail = '...'): string {
    return value.length > limit
      ? value.substring(0, limit) + trail
      : value;
  }
}

import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';

@Injectable({
  providedIn: 'root'   // tree-shakable, app-wide singleton
})
export class AuthService {
  private http = inject(HttpClient);  // inject() function — Angular 21 preferred

  login(credentials: { email: string; password: string }) {
