  form = this.fb.group({
    email: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, Validators.minLength(8)]]
  });

  onSubmit() {
    if (this.form.valid) console.log(this.form.value);
  }
}

import { Component, signal, computed, effect } from '@angular/core';

@Component({
  standalone: true,
  selector: 'app-cart',
  template: `
    <p>Items: {{ itemCount() }}</p>
    <p>Total: {{ total() | currency }}</p>
    <button (click)="addItem()">Add Item</button>
  `
})
export class CartComponent {
  items = signal<{ name: string; price: number }[]>([]);

  // Derived state — auto-updates when items changes
  itemCount = computed(() => this.items().length);
  total = computed(() => this.items().reduce((sum, i) => sum + i.price, 0));

  constructor() {
    // Side effect — runs when dependency changes
    effect(() => {
      console.log(`Cart updated: ${this.itemCount()} items`);
    });
  }

  addItem() {
    this.items.update(list => [...list, { name: 'Product', price: 499 }]);
  }
}
